import React, { useState } from 'react';

function Admin() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [formData, setFormData] = useState({
    username: '',
    email: '',
    newPassword: '',
    confirmPassword: ''
  });
  const [success, setSuccess] = useState(false);

  const handleLogin = (e) => {
    e.preventDefault();
    if (password === '0000') {
      setIsAuthenticated(true);
      setError('');
    } else {
      setError('Invalid temporary password');
    }
  };

  const handleCreateAccount = (e) => {
    e.preventDefault();
    if (formData.newPassword !== formData.confirmPassword) {
      setError('Passwords do not match');
      return;
    }

    // Simulate account creation
    const admins = JSON.parse(localStorage.getItem('admin_accounts') || '[]');
    admins.push({
      username: formData.username,
      email: formData.email,
      password: formData.newPassword // In a real app, this should be hashed
    });
    localStorage.setItem('admin_accounts', JSON.stringify(admins));

    setSuccess(true);
    setError('');
    setFormData({ username: '', email: '', newPassword: '', confirmPassword: '' });
    setTimeout(() => setSuccess(false), 3000);
  };

  if (!isAuthenticated) {
    return (
      <div className="flex items-center justify-center min-h-[70vh] fade-in">
        <div className="bg-white p-10 rounded-3xl shadow-xl border border-gray-100 w-full max-w-md">
          <div className="text-center mb-8">
            <h2 className="text-3xl font-bold text-gray-900 mb-2">Admin Portal</h2>
            <p className="text-gray-500">Please enter the temporary password</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-6">
            <div>
              <input
                type="password"
                placeholder="Temporary Password (0000)"
                className="w-full px-6 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:outline-none focus:ring-2 focus:ring-brand-brown/20 focus:border-brand-brown transition-all text-center text-2xl tracking-widest font-bold"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
              />
            </div>
            {error && <p className="text-red-500 text-sm text-center font-medium">{error}</p>}
            <button
              type="submit"
              className="w-full py-4 bg-brand-brown text-white rounded-2xl font-bold shadow-lg hover:shadow-xl hover:-translate-y-0.5 transition-all"
            >
              Access Admin Page
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="fade-in max-w-4xl mx-auto pb-20 px-6">
      <header className="mb-12 text-center">
        <h1 className="text-4xl font-bold text-gray-900 mb-3">Management Admin</h1>
        <p className="text-lg text-gray-500">Create and manage institutional admin accounts</p>
      </header>

      <div className="bg-white rounded-3xl shadow-xl border border-gray-100 overflow-hidden">
        <div className="p-8 md:p-12 border-b border-gray-100">
          <h2 className="text-2xl font-bold text-gray-900 mb-6">Create New Admin Account</h2>

          {success && (
            <div className="mb-8 p-4 bg-green-50 text-green-700 rounded-2xl border border-green-100 text-center font-medium animate-pulse">
              Account created successfully!
            </div>
          )}

          {error && (
            <div className="mb-8 p-4 bg-red-50 text-red-700 rounded-2xl border border-red-100 text-center font-medium">
              {error}
            </div>
          )}

          <form onSubmit={handleCreateAccount} className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-sm font-bold text-gray-700 ml-1">Full Name / Username</label>
              <input
                type="text"
                required
                className="w-full px-6 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:outline-none focus:ring-2 focus:ring-brand-brown/20 focus:border-brand-brown transition-all"
                placeholder="e.g. Registrar Office"
                value={formData.username}
                onChange={(e) => setFormData({...formData, username: e.target.value})}
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-bold text-gray-700 ml-1">Email Address</label>
              <input
                type="email"
                required
                className="w-full px-6 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:outline-none focus:ring-2 focus:ring-brand-brown/20 focus:border-brand-brown transition-all"
                placeholder="admin@indusuni.ac.in"
                value={formData.email}
                onChange={(e) => setFormData({...formData, email: e.target.value})}
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-bold text-gray-700 ml-1">New Password</label>
              <input
                type="password"
                required
                className="w-full px-6 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:outline-none focus:ring-2 focus:ring-brand-brown/20 focus:border-brand-brown transition-all"
                placeholder="••••••••"
                value={formData.newPassword}
                onChange={(e) => setFormData({...formData, newPassword: e.target.value})}
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-bold text-gray-700 ml-1">Confirm Password</label>
              <input
                type="password"
                required
                className="w-full px-6 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:outline-none focus:ring-2 focus:ring-brand-brown/20 focus:border-brand-brown transition-all"
                placeholder="••••••••"
                value={formData.confirmPassword}
                onChange={(e) => setFormData({...formData, confirmPassword: e.target.value})}
              />
            </div>
            <div className="md:col-span-2 pt-4">
              <button
                type="submit"
                className="w-full md:w-auto px-12 py-4 bg-brand-brown text-white rounded-2xl font-bold shadow-lg hover:shadow-xl hover:-translate-y-0.5 transition-all text-lg"
              >
                Register Admin Account
              </button>
            </div>
          </form>
        </div>

        <div className="bg-gray-50 p-8 md:p-12">
          <h3 className="text-xl font-bold text-gray-900 mb-4">Security Notice</h3>
          <p className="text-gray-600 text-sm leading-relaxed">
            All administrative actions are logged for security purposes. Admin accounts created here will have full access to the institutional management features. Please ensure that you assign roles to trusted personnel only.
          </p>
        </div>
      </div>
    </div>
  );
}

export default Admin;
